mapper.insert:
/* 전역 중복요청 방지: 지문 등록 시도 */
INSERT INTO REQ_FGPT (RQF_HASH, RQF_EXP_DT)
VALUES (#{hash}, #{expDt})

mapper.select:
/* 전역 중복요청 방지: 지문 응답 조회 */
SELECT RQF_RESP_STAT AS RQF_RESP_STAT,
       RQF_RESP_BODY AS RQF_RESP_BODY
  FROM REQ_FGPT
 WHERE RQF_HASH = #{hash}

mapper.update:
/* 전역 중복요청 방지: 응답 저장 */
UPDATE REQ_FGPT
   SET RQF_RESP_STAT = #{status},
       RQF_RESP_BODY = #{body}
 WHERE RQF_HASH = #{hash}

mapper.delete:
/* 전역 중복요청 방지: 만료 지문 삭제 */
DELETE FROM REQ_FGPT
 WHERE RQF_EXP_DT < #{now}
 LIMIT 1000
